import React, { useEffect, useState } from 'react';
import { listUsers, addUser, updateUser, deleteUser } from '../../services/mockApi';
import { v4 as uuidv4 } from 'uuid';
import {
  FiUserPlus, FiEdit2, FiTrash2, FiCheck, FiX, FiSearch,
  FiPlus, FiMinus
} from 'react-icons/fi';

const ROLES_KEY = 'user-management-roles';
const DEPARTMENTS_KEY = 'user-management-departments';

const defaultRoles = [
  'Admin', 'Manager', 'Developer', 'Reporter',
  'Senior Associate Developer', 'Associate Developer', 'HR', 'Administrator'
];
const defaultDepartments = [
  'Engineering', 'Sales', 'HR', 'Marketing',
  'Frontend', 'Backend', 'Middleware', 'AIML',
  'DevOps', 'Testing', 'Flowtrack', 'Network', 'Administrator'
];

function getStored(key, fallback) {
  const saved = localStorage.getItem(key);
  try {
    return saved ? JSON.parse(saved) : fallback;
  } catch {
    return fallback;
  }
}
function setStored(key, value) {
  localStorage.setItem(key, JSON.stringify(value));
}

export default function Users() {
  const defaultNewUser = {
    firstName: '',
    lastName: '',
    email: '',
    role: 'Developer',
    department: 'Engineering',
    active: true,
    language: 'English',
    mobileNumber: '',
    passwordResetNeeded: false,
    profileFile: null,
  };

  const [users, setUsers] = useState([]);
  const [newUserForm, setNewUserForm] = useState(defaultNewUser);
  const [editingId, setEditingId] = useState(null);
  const [editForm, setEditForm] = useState({});
  const [searchTerm, setSearchTerm] = useState('');
  const [error, setError] = useState(null);

  // Roles & Departments state
  const [roles, setRoles] = useState(() => getStored(ROLES_KEY, defaultRoles));
  const [departments, setDepartments] = useState(() => getStored(DEPARTMENTS_KEY, defaultDepartments));

  // Modal state
  const [showRoleModal, setShowRoleModal] = useState(false);
  const [showDepartmentModal, setShowDepartmentModal] = useState(false);
  const [roleInput, setRoleInput] = useState('');
  const [departmentInput, setDepartmentInput] = useState('');
  const [roleToDelete, setRoleToDelete] = useState('');
  const [departmentToDelete, setDepartmentToDelete] = useState('');

  // Load users on mount
  useEffect(() => {
    const fetchUsers = async () => {
      try {
        const response = await fetch("http://localhost:8000/admin");
        if (response.ok) {
          const data = await response.json();
          setUsers(data);
        } else {
          setError("Failed to load users from backend");
        }
      } catch (err) {
        console.error('Failed to load users:', err);
        setError('Failed to load users');
      }
    };
    fetchUsers();
  }, []);

  // Save roles and departments to localStorage if changed
  useEffect(() => { setStored(ROLES_KEY, roles); }, [roles]);
  useEffect(() => { setStored(DEPARTMENTS_KEY, departments); }, [departments]);

  // Handlers
  const handleNewUserChange = (e) => {
    const { name, value, type, checked, files } = e.target;
    setNewUserForm(prev => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : (type === 'file' ? files[0] : value),
    }));
  };

  const handleEditChange = (e) => {
    const { name, value, type, checked, files } = e.target;
    setEditForm(prev => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : (type === 'file' ? files[0] : value),
    }));
  };

  const create = async () => {
    if (!newUserForm.firstName.trim() || !newUserForm.lastName.trim() || !newUserForm.email.trim()) {
      setError('First Name, Last Name, and Email are required.');
      return;
    }
    try {
      const newUser = {
        id: uuidv4(),
        ...newUserForm,
        name: `${newUserForm.firstName.trim()} ${newUserForm.lastName.trim()}`,
        profileFile: newUserForm.profileFile
          ? { name: newUserForm.profileFile.name, size: newUserForm.profileFile.size }
          : null
      };
      await addUser(newUser);
      const updatedUsers = await listUsers();
      setUsers(updatedUsers);
      setNewUserForm(defaultNewUser);
      setError(null);
    } catch (err) {
      console.error('Failed to add user:', err);
      setError('Failed to add user');
    }
  };

  const startEdit = (u) => {
    setEditingId(u.id);
    setEditForm({ ...u });
    setError(null);
  };

  const cancelEdit = () => {
    setEditingId(null);
    setEditForm({});
    setError(null);
  };

  const saveEdit = async (id) => {
    if (!editForm.full_name.trim() || !editForm.email.trim()) {
      setError('Full Name and Email cannot be empty.');
      return;
    }
    try {
      const response = await fetch(`http://localhost:8000/admin/${id}`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          full_name: editForm.full_name.trim(),
          email: editForm.email.trim()
        }),
      });

      if (response.ok) {
        // Refresh the users list
        const profilesResponse = await fetch("http://localhost:8000/admin");
        if (profilesResponse.ok) {
          const profilesData = await profilesResponse.json();
          setUsers(profilesData);
        }
        cancelEdit();
        setError(null);
      } else {
        const errorData = await response.json();
        setError("Failed to update user: " + (errorData.detail || "Unknown error"));
      }
    } catch (err) {
      console.error('Failed to update user:', err);
      setError('User not found or failed to update');
    }
  };

  const remove = async (id) => {
    try {
      const response = await fetch(`http://localhost:8000/admin/${id}`, {
        method: 'DELETE',
      });

      if (response.ok) {
        // Refresh the users list
        const profilesResponse = await fetch("http://localhost:8000/admin");
        if (profilesResponse.ok) {
          const profilesData = await profilesResponse.json();
          setUsers(profilesData);
        }
        setError(null);
      } else {
        const errorData = await response.json();
        setError("Failed to delete user: " + (errorData.detail || "Unknown error"));
      }
    } catch (err) {
      console.error('Failed to delete user:', err);
      setError('User not found or failed to delete');
    }
  };

  const filteredUsers = users.filter(user => {
    const searchLower = searchTerm.toLowerCase();
    return (
      (user.full_name && user.full_name.toLowerCase().includes(searchLower)) ||
      (user.email && user.email.toLowerCase().includes(searchLower))
    );
  });

  const getRoleColor = (roleOrDepartment) => {
    const colors = {
      'admin': 'role-admin',
      'manager': 'role-manager',
      'developer': 'role-developer',
      'reporter': 'role-reporter',
      'engineering': 'role-developer',
      'sales': 'role-sales',
      'hr': 'role-hr',
      'marketing': 'role-marketing',
      'senior associate developer': 'role-developer',
      'associate developer': 'role-developer',
      'frontend': 'role-developer',
      'backend': 'role-developer',
      'middleware': 'role-developer',
      'aiml': 'role-developer',
      'devops': 'role-developer',
      'testing': 'role-developer',
      'flowtrack': 'role-developer',
      'network': 'role-developer',
      'administrator': 'role-admin',
    };
    return colors[roleOrDepartment.toLowerCase()] || '';
  };

  // ---- Modal handlers ----
  // Role modals
  const openRoleModal = () => { setShowRoleModal(true); setRoleInput(''); setRoleToDelete(''); };
  const closeRoleModal = () => { setShowRoleModal(false); setRoleInput(''); setRoleToDelete(''); };

  const addRole = () => {
    const v = roleInput.trim();
    if (v && !roles.includes(v)) {
      setRoles([...roles, v]);
      setRoleInput('');
    }
  };
  const deleteRole = (r) => {
    setRoles(roles.filter(role => role !== r));
    if (newUserForm.role === r) setNewUserForm(prev => ({ ...prev, role: roles[0] || '' }));
    if (editForm.role === r) setEditForm(prev => ({ ...prev, role: roles[0] || '' }));
    setRoleToDelete('');
  };

  // Department modals
  const openDepartmentModal = () => { setShowDepartmentModal(true); setDepartmentInput(''); setDepartmentToDelete(''); };
  const closeDepartmentModal = () => { setShowDepartmentModal(false); setDepartmentInput(''); setDepartmentToDelete(''); };

  const addDepartment = () => {
    const v = departmentInput.trim();
    if (v && !departments.includes(v)) {
      setDepartments([...departments, v]);
      setDepartmentInput('');
    }
  };
  const deleteDepartment = (d) => {
    setDepartments(departments.filter(dep => dep !== d));
    if (newUserForm.department === d)
      setNewUserForm(prev => ({ ...prev, department: departments[0] || '' }));
    if (editForm.department === d)
      setEditForm(prev => ({ ...prev, department: departments[0] || '' }));
    setDepartmentToDelete('');
  };

  return (
    <div className="users-container">
      <style jsx global>{`
        body { background: #D8F7FA; min-height: 100vh; }
      `}</style>
      {/* Header */}
      <div className="users-header">
        <h1 className="users-title">User Management System 🧑‍💼</h1>
        <p className="users-subtitle">Manage your team members, roles, and administrative settings.</p>
        {error && <p className="error-message">{error}</p>}
      </div>
      <div className="users-grid">
        {/* FORM SECTION */}
        <div className="users-form-card glassmorphism" aria-labelledby="users-form-title">
          <div className="card-header">
            <h2 id="users-form-title" className="card-title">
              <FiUserPlus className="icon-spacing" /> Add New User
            </h2>
          </div>
          <div className="form-grid-expanded">
            <div className="input-group">
              <label className="input-label">Full Name *</label>
              <input className="modern-input" name="firstName"
                value={newUserForm.firstName}
                onChange={handleNewUserChange}
                placeholder="Full Name"
              />
            </div>
            <div className="input-group">
              <label className="input-label">Email Address *</label>
              <input className="modern-input" name="email"
                value={newUserForm.email}
                onChange={handleNewUserChange}
                placeholder="Email Address"
                type="email"
              />
            </div>
            <div className="input-group">
              <label className="input-label">Mobile Number</label>
              <input className="modern-input" name="mobileNumber"
                value={newUserForm.mobileNumber}
                onChange={handleNewUserChange}
                placeholder="Mobile Number"
                type="tel"
              />
            </div>
            {/* Role dropdown with add/delete */}
            <div className="input-group" style={{ position: 'relative' }}>
              <label className="input-label">Role
                <FiPlus style={{ cursor: 'pointer', marginLeft: 8, color: '#667eea' }}
                  onClick={openRoleModal} title="Edit roles" />
              </label>
              <select className="modern-select" name="role"
                value={newUserForm.role}
                onChange={handleNewUserChange}>
                {roles.map(r => (
                  <option key={r}>{r}</option>
                ))}
              </select>
            </div>
            {/* Department dropdown with add/delete */}
            <div className="input-group" style={{ position: 'relative' }}>
              <label className="input-label">Department
                <FiPlus style={{ cursor: 'pointer', marginLeft: 8, color: '#667eea' }}
                  onClick={openDepartmentModal} title="Edit departments" />
              </label>
              <select className="modern-select" name="department"
                value={newUserForm.department}
                onChange={handleNewUserChange}>
                {departments.map(d => (
                  <option key={d}>{d}</option>
                ))}
              </select>
            </div>
            <div className="input-group checkbox-group">
              <label className="input-label">User Status</label>
              <label className="checkbox-label">
                <input
                  type="checkbox"
                  name="active"
                  checked={newUserForm.active}
                  onChange={handleNewUserChange}
                />
                <span className="checkbox-text">{newUserForm.active ? 'Active' : 'Inactive'}</span>
              </label>
            </div>
            <div className="input-group checkbox-group">
              <label className="input-label">Password Reset</label>
              <label className="checkbox-label">
                <input
                  type="checkbox"
                  name="passwordResetNeeded"
                  checked={newUserForm.passwordResetNeeded}
                  onChange={handleNewUserChange}
                />
                <span className="checkbox-text">Reset on next login</span>
              </label>
            </div>
          </div>
          <button className="create-btn" onClick={create}>
            <FiUserPlus className="btn-icon" />
            Create User
          </button>
        </div>
        {/* LIST SECTION */}
        <div className="users-list-card glassmorphism" aria-labelledby="users-list-title">
          <div className="card-header">
            <h2 id="users-list-title" className="card-title">
              Team Members ({filteredUsers.length})
            </h2>
            <div className="search-container">
              <FiSearch className="search-icon" />
              <input
                type="text"
                className="search-input"
                placeholder="Search users..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
          </div>
          <div className="table-container">
            <table className="modern-table" role="table" aria-label="Users table">
              <thead>
                <tr>
                  <th>Name</th>
                  <th>Email</th>
                  <th>Department</th>
                  <th>Role</th>
                  <th>Active</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody>
                {filteredUsers.map(u => (
                  <tr key={u.id} className={editingId === u.id ? 'editing-row' : ''}>
                    {editingId === u.id ? (
                      <>
                        <td>
                          <input className="edit-input" name="full_name"
                            value={editForm.full_name || ''}
                            onChange={handleEditChange}
                            placeholder="Full Name"
                          />
                        </td>
                        <td>
                          <input className="edit-input" name="email"
                            value={editForm.email || ''}
                            onChange={handleEditChange}
                          />
                        </td>
                        <td>
                          <input className="edit-input" value="Admin Portal" disabled />
                        </td>
                        <td>
                          <input className="edit-input" value="Administrator" disabled />
                        </td>
                        <td>
                          <input type="checkbox" checked={true} disabled />
                        </td>
                        <td>
                          <div className="action-buttons">
                            <button onClick={() => saveEdit(u.id)} className="btn-success" title="Save">
                              <FiCheck />
                            </button>
                            <button onClick={cancelEdit} className="btn-cancel" title="Cancel">
                              <FiX />
                            </button>
                          </div>
                        </td>
                      </>
                    ) : (
                      <>
                        <td>
                          <div className="user-info">
                            <div className="avatar">{u.full_name ? u.full_name.charAt(0) : 'A'}</div>
                            <span>{u.full_name}</span>
                          </div>
                        </td>
                        <td>{u.email}</td>
                        <td>
                          <span className={`role-badge ${getRoleColor('admin')}`}>
                            Admin Portal
                          </span>
                        </td>
                        <td>
                          <span className={`role-badge ${getRoleColor('administrator')}`}>
                            Administrator
                          </span>
                        </td>
                        <td>
                          <span className={`status-dot status-active`}></span>
                        </td>
                        <td>
                          <div className="action-buttons">
                            <button onClick={() => startEdit(u)} className="btn-edit" title="Edit">
                              <FiEdit2 />
                            </button>
                            <button onClick={() => remove(u.id)} className="btn-delete" title="Delete">
                              <FiTrash2 />
                            </button>
                          </div>
                        </td>
                      </>
                    )}
                  </tr>
                ))}
              </tbody>
            </table>
            {filteredUsers.length === 0 && (
              <div className="empty-state">
                <p>No users found{searchTerm && ` matching "${searchTerm}"`}</p>
              </div>
            )}
          </div>
        </div>
      </div>

      {/* MODALS */}
      {showRoleModal && (
        <div className="modal-overlay">
          <div className="modal-content">
            <h3>Edit Roles</h3>
            <div style={{ marginBottom: 12 }}>
              <input type="text"
                placeholder="Add new role"
                className="modern-input"
                value={roleInput}
                onChange={e => setRoleInput(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && addRole()}
              />
              <button onClick={addRole} className="create-btn" style={{ marginTop: 8, fontSize: '1rem' }}>Add</button>
            </div>
            <div>
              {roles.map(r => (
                <div key={r} style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 4 }}>
                  <span>{r}</span>
                  <FiMinus style={{ cursor: 'pointer', color: '#e53e3e' }}
                    title="Delete role"
                    onClick={() => setRoleToDelete(r)}
                  />
                  {roleToDelete === r && (
                    <span style={{ marginLeft: 6 }}>
                      Delete?
                      <button className="btn-delete" onClick={() => deleteRole(r)} style={{ marginLeft: 3, fontSize: '0.9rem' }}>Yes</button>
                      <button className="btn-cancel" style={{ marginLeft: 3, fontSize: '0.9rem' }} onClick={() => setRoleToDelete('')}>No</button>
                    </span>
                  )}
                </div>
              ))}
            </div>
            <button className="btn-cancel" style={{ marginTop: 16 }} onClick={closeRoleModal}>Close</button>
          </div>
        </div>
      )}

      {showDepartmentModal && (
        <div className="modal-overlay">
          <div className="modal-content">
            <h3>Edit Departments</h3>
            <div style={{ marginBottom: 12 }}>
              <input type="text"
                placeholder="Add new department"
                className="modern-input"
                value={departmentInput}
                onChange={e => setDepartmentInput(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && addDepartment()}
              />
              <button onClick={addDepartment} className="create-btn" style={{ marginTop: 8, fontSize: '1rem' }}>Add</button>
            </div>
            <div>
              {departments.map(d => (
                <div key={d} style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 4 }}>
                  <span>{d}</span>
                  <FiMinus
                    style={{ cursor: 'pointer', color: '#e53e3e' }}
                    title="Delete department"
                    onClick={() => setDepartmentToDelete(d)}
                  />
                  {departmentToDelete === d && (
                    <span style={{ marginLeft: 6 }}>
                      Delete?
                      <button className="btn-delete" onClick={() => deleteDepartment(d)} style={{ marginLeft: 3, fontSize: '0.9rem' }}>Yes</button>
                      <button className="btn-cancel" style={{ marginLeft: 3, fontSize: '0.9rem' }} onClick={() => setDepartmentToDelete('')}>No</button>
                    </span>
                  )}
                </div>
              ))}
            </div>
            <button className="btn-cancel" style={{ marginTop: 16 }} onClick={closeDepartmentModal}>Close</button>
          </div>
        </div>
      )}

      {/* --- Modal Styles --- */}
      <style jsx>{`
        .modal-overlay {
          position: fixed; top: 0; left: 0; right: 0; bottom: 0;
          background: rgba(0,0,0,.15);
          z-index: 1100;
          display: flex;
          justify-content: center;
          align-items: center;
        }
        .modal-content {
          background: #fff;
          border-radius: 12px;
          padding: 30px 35px;
          box-shadow: 0 8px 32px rgba(0,0,0,.15);
          min-width: 350px;
          max-width: 95vw;
          font-size: 1.03rem;
          color: #2d3748;
        }
        .modal-content h3 { margin-top:0; font-size:1.18em; margin-bottom:0.9em; }
        .modal-content input { margin-bottom:6px; }

        .users-container {
          min-height: 100vh;
          background: #D8F7FA;
          padding: 20px;
        }
        .users-header {
          text-align: center;
          margin-bottom: 40px;
          color: #2d3748;
        }
        .users-title {
          font-size: 2.5rem;
          font-weight: 700;
          margin-bottom: 8px;
        }
        .users-subtitle {
          font-size: 1.1rem;
          opacity: 0.8;
          color: #4a5568;
        }
        .error-message {
          color: #e53e3e;
          background: #fed7d7;
          padding: 8px 15px;
          border-radius: 8px;
          margin-top: 15px;
          display: inline-block;
          font-weight: 500;
        }
        .users-grid {
          display: grid;
          grid-template-columns: 1fr;
          gap: 30px;
          max-width: 1400px;
          margin: 0 auto;
        }
        @media (min-width: 1024px) {
          .users-grid {
            grid-template-columns: 450px 1fr;
          }
        }
        .glassmorphism {
          background: rgba(255, 255, 255, 0.95);
          backdrop-filter: blur(10px);
          border-radius: 20px;
          border: 1px solid rgba(255, 255, 255, 0.2);
          box-shadow: 0 8px 32px rgba(0, 0, 0, 0.05);
        }
        .users-form-card,
        .users-list-card {
          padding: 30px;
        }
        .card-header {
          display: flex;
          justify-content: space-between;
          align-items: center;
          margin-bottom: 30px;
          flex-wrap: wrap;
          gap: 15px;
        }
        .card-title {
          font-size: 1.5rem;
          font-weight: 600;
          color: #2d3748;
          display: flex;
          align-items: center;
        }
        .icon-spacing {
          margin-right: 10px;
        }
        .form-grid-expanded {
          display: grid;
          grid-template-columns: 1fr 1fr;
          gap: 20px;
          margin-bottom: 30px;
        }
        .input-group {
          display: flex;
          flex-direction: column;
        }
        .input-label {
          font-weight: 500;
          margin-bottom: 8px;
          color: #4a5568;
        }
        .checkbox-group {
          grid-column: span 1;
        }
        .checkbox-label {
          display: flex;
          align-items: center;
          font-weight: 400;
          color: #4a5568;
          cursor: pointer;
          padding: 10px;
          border-radius: 8px;
        }
        .checkbox-label input[type="checkbox"] {
          margin-right: 10px;
          width: 18px;
          height: 18px;
          accent-color: #667eea;
        }
        .file-group input[type="file"] {
          display: none;
        }
        .file-upload-btn {
          padding: 12px 16px;
          border: 2px solid #667eea;
          border-radius: 10px;
          font-size: 1rem;
          font-weight: 500;
          color: #667eea;
          background: #ebf4ff;
          cursor: pointer;
          transition: background-color 0.2s;
          display: flex;
          align-items: center;
          justify-content: flex-start;
        }
        .file-upload-btn:hover {
          background: #d4e3ff;
        }
        .file-upload-btn .btn-icon {
          margin-right: 8px;
          font-size: 1.2rem;
        }
        .modern-input,
        .modern-select {
          padding: 12px 16px;
          border: 2px solid #e2e8f0;
          border-radius: 10px;
          font-size: 1rem;
          transition: all 0.3s ease;
          width: 100%;
          box-sizing: border-box;
        }
        .modern-input:focus,
        .modern-select:focus {
          outline: none;
          border-color: #667eea;
          box-shadow: 0 0 0 3px rgba(102, 126, 234, 0.1);
        }
        .create-btn {
          grid-column: 1 / -1;
          width: 100%;
          padding: 14px;
          background: #4e54c8;
          color: white;
          border: none;
          border-radius: 10px;
          font-size: 1rem;
          font-weight: 600;
          cursor: pointer;
          transition: transform 0.2s ease;
          display: flex;
          align-items: center;
          justify-content: center;
        }
        .create-btn:hover {
          transform: translateY(-2px);
          box-shadow: 0 4px 12px rgba(102, 126, 234, 0.4);
        }
        .btn-icon {
          margin-right: 8px;
        }
        .search-container {
          position: relative;
          min-width: 250px;
        }
        .search-input {
          padding: 12px 16px 12px 40px;
          border: 2px solid #e2e8f0;
          border-radius: 10px;
          font-size: 1rem;
          width: 100%;
          transition: all 0.3s ease;
        }
        .search-input:focus {
          outline: none;
          border-color: #667eea;
          box-shadow: 0 0 0 3px rgba(102, 126, 234, 0.1);
        }
        .search-icon {
          position: absolute;
          left: 12px;
          top: 50%;
          transform: translateY(-50%);
          color: #a0aec0;
        }
        .table-container {
          border-radius: 10px;
        }
        .modern-table {
          width: 100%;
          border-collapse: collapse;
          table-layout: auto;
        }
        .modern-table th {
          background: #f7fafc;
          padding: 12px 8px;
          text-align: left;
          font-weight: 600;
          color: #4a5568;
          border-bottom: 2px solid #e2e8f0;
          word-wrap: break-word;
        }
        .modern-table td {
          padding: 12px 8px;
          border-bottom: 1px solid #e2e8f0;
          vertical-align: middle;
          word-wrap: break-word;
          white-space: normal;
        }
        .modern-table tr:hover {
          background: #D8F7FA;
        }
        .editing-row {
          background: #fff9e6 !important;
        }
        .user-info {
          display: flex;
          align-items: center;
          gap: 12px;
          flex-wrap: wrap;
          white-space: normal;
        }
        .file-indicator {
          font-size: 1.1em;
          cursor: help;
          white-space: nowrap;
        }
        .avatar {
          width: 40px;
          height: 40px;
          border-radius: 50%;
          background:#4e54c8;
          display: flex;
          align-items: center;
          justify-content: center;
          color: white;
          font-weight: 600;
          font-size: 1.1rem;
          flex-shrink: 0;
        }
        .status-dot {
