          border-radius: 20px;
          font-size: 0.85rem;
          font-weight: 500;
          white-space: nowrap;
        }
        .role-admin {
          background: #fed7d7;
          color: #c53030;
        }
        .role-manager {
          background: #feebc8;
          color: #d69e2e;
        }
        .role-developer, .role-engineering {
          background: #c6f6d5;
          color: #276749;
        }
        .role-reporter {
          background: #e9d8fd;
          color: #6b46c1;
        }
        .role-sales {
          background: #bee3f8;
          color: #2c5282;
        }
        .role-hr {
          background: #fff0f5;
          color: #d53f8c;
        }
        .role-marketing {
          background: #faf089;
          color: #744210;
        }
        .action-buttons {
          display: flex;
          gap: 8px;
          flex-wrap: wrap;
        }
        .btn-edit,
        .btn-delete,
        .btn-success,
        .btn-cancel {
          padding: 8px;
          border: none;
          border-radius: 8px;
          cursor: pointer;
          transition: all 0.2s ease;
          display: flex;
          align-items: center;
          justify-content: center;
        }
        .btn-edit {
          background: #e6fffa;
          color: #234e52;
        }
        .btn-edit:hover {
          background: #b2f5ea;
        }
        .btn-delete {
          background: #fed7d7;
          color: #c53030;
        }
        .btn-delete:hover {
          background: #feb2b2;
        }
        .btn-success {
          background: #c6f6d5;
          color: #276749;
        }
        .btn-success:hover {
          background: #9ae6b4;
        }
        .btn-cancel {
          background: #fed7d7;
          color: #c53030;
        }
        .btn-cancel:hover {
          background: #feb2b2;
        }
        .edit-input,
        .edit-select {
          padding: 8px 12px;
          border: 2px solid #e2e8f0;
          border-radius: 6px;
          width: 100%;
          font-size: 0.9rem;
          box-sizing: border-box;
        }
        .edit-input:focus,
        .edit-select:focus {
          outline: none;
          border-color: #667eea;
        }
        .empty-state {
          text-align: center;
          padding: 40px;
          color: #a0aec0;
          font-style: italic;
        }
        @media (max-width: 1024px) {
          .form-grid-expanded {
            grid-template-columns: 1fr;
          }
          .users-grid {
            grid-template-columns: 1fr;
          }
        }
        @media (max-width: 768px) {
          .users-container {
            padding: 10px;
          }
          .users-title {
            font-size: 2rem;
          }
          .users-form-card,
          .users-list-card {
            padding: 20px;
          }
          .card-header {
            flex-direction: column;
            align-items: stretch;
          }
          .search-container {
            min-width: auto;
          }
          .modern-table {
            font-size: 0.85rem;
          }
          .modern-table th,
          .modern-table td {
            padding: 8px 6px;
          }
          .action-buttons {
            flex-direction: row;
          }
          .user-info {
            gap: 6px;
          }
        }
        @media (max-width: 480px) {
          .users-title {
            font-size: 1.75rem;
          }
          .card-title {
            font-size: 1.25rem;
          }
          .user-info {
            flex-direction: column;
            text-align: center;
            align-items: flex-start;
          }
          .avatar {
            width: 32px;
            height: 32px;
            font-size: 1rem;
          }
        }
      `}</style>
    </div>
  );
